bool isAnagram(const string &s, const string &t) {
    if (s.length() != t.length())
        return false;

    int count[26] = {0};

    for (char c : s)
        count[c - 'a']++;

    for (char c : t)
        count[c - 'a']--;

    for (int i = 0; i < 26; i++)
        if (count[i] != 0)
            return false;

    return true;
}

code.Python3:
def isAnagram(s, t):
    if len(s) != len(t):
        return False

    count = [0] * 26  # For 'a' to 'z'

    for ch in s:
        count[ord(ch) - ord('a')] += 1

    for ch in t:
        count[ord(ch) - ord('a')] -= 1

    for c in count:
        if c != 0:
            return False

    return True

